<?php get_header(); $channel = get_query_var( 'cpwp_public_channel' ); $owner = absint( get_query_var( 'cpwp_channel_owner' ) ); $videos = new WP_Query( array( 'post_type' => 'cp_video', 'posts_per_page' => 30, 'meta_key' => '_cpwp_channel_owner', 'meta_value' => $owner ) ); ?>
<div class="cp-shell" style="--cp-accent:<?php echo esc_attr( $channel['accent_color'] ?? '#6d5dfc' ); ?>"><?php if ( ! empty( $channel['banner_url'] ) ) : ?><img class="cp-channel-banner" src="<?php echo esc_url( $channel['banner_url'] ); ?>" alt=""><?php endif; ?><header class="cp-channel-hero"><img src="<?php echo esc_url( $channel['logo_url'] ?: get_avatar_url( $owner ) ); ?>" alt=""><div><span class="cp-kicker"><?php echo esc_html( $channel['category'] ?? 'Creator channel' ); ?></span><h1><?php echo esc_html( $channel['name'] ); ?> <?php if ( 'approved' === get_user_meta( $owner, CPWP_Creator_Platform::VERIFY_STATUS, true ) ) : ?>&#10003;<?php endif; ?></h1><p><?php echo esc_html( $channel['description'] ); ?></p><span><?php echo esc_html( $videos->found_posts ); ?> videos · <strong data-cpwp-subscriber-count><?php echo esc_html( count( CPWP_Channels::followers( $owner ) ) ); ?></strong> subscribers</span><?php if ( get_current_user_id() !== $owner ) : ?><p><button class="cp-button" data-cpwp-follow-channel="<?php echo esc_attr( $owner ); ?>"><?php esc_html_e( 'Follow', 'cp-theme' ); ?></button> <button class="cp-button" data-cpwp-sub-preferences="<?php echo esc_attr( $owner ); ?>">Preferences</button></p><?php endif; ?></div></header><?php if ( ! empty( $channel['featured_video'] ) ) : ?><section class="cp-section"><h2>Featured</h2><?php cp_theme_video_card( absint( $channel['featured_video'] ) ); ?></section><?php endif; ?><section class="cp-section"><h2><?php esc_html_e( 'Channel videos', 'cp-theme' ); ?></h2><div class="cp-theme-grid"><?php while ( $videos->have_posts() ) : $videos->the_post(); cp_theme_video_card( get_the_ID() ); endwhile; wp_reset_postdata(); ?></div></section></div>
<?php get_footer(); ?>
